export async function runGoalAudit({ root = new URL("../../", import.meta.url).pathname } = {}) {
  const items = [];
  for (const check of CHECKS) {
    const verified = await check.verify(root);
    items.push({
      id: check.id,
      requirement: check.requirement,
      status: verified ? check.status : "missing",
      evidence: check.evidence,
    });
  }

  const summary = {
    met: items.filter((item) => item.status === "met").length,
    partial: items.filter((item) => item.status === "partial").length,
    missing: items.filter((item) => item.status === "missing").length,
    total: items.length,
  };

  return {
    objective: OBJECTIVE,
    complete: summary.partial === 0 && summary.missing === 0,
    summary,
    items,
  };
}

export function formatGoalAudit(audit) {
  const lines = [
    `Objective: ${audit.objective}`,
    `Complete: ${audit.complete ? "yes" : "no"}`,
    `Summary: ${audit.summary.met} met, ${audit.summary.partial} partial, ${audit.summary.missing} missing, ${audit.summary.total} total`,
    "",
    "Missing or partial requirements:",
  ];

  for (const item of audit.items.filter((entry) => entry.status !== "met")) {
    lines.push(`- [${item.status}] ${item.id}: ${item.requirement}`);
    for (const evidence of item.evidence) {
      lines.push(`  evidence: ${evidence}`);
    }
  }

  return `${lines.join("\n")}\n`;
}

function allFiles(paths) {
  return async (root) => {
    for (const path of paths) {
      if (!(await fileExists(join(root, path)))) {
        return false;
      }
    }
    return true;
  };
}

function allOf(...checks) {
  return async (root) => {
    for (const check of checks) {
      if (!(await check(root))) {
        return false;
      }
    }
    return true;
  };
}

function fileIncludes(path, needles) {
  return async (root) => {
    const content = await readText(join(root, path));
    return needles.every((needle) => content.includes(needle));
  };
}

async function packageHasNoDependencies(root) {
  const pkg = JSON.parse(await readText(join(root, "package.json")));
  return !pkg.dependencies && !pkg.devDependencies && !pkg.optionalDependencies;
}

async function fileExists(path) {
  try {
    const info = await stat(path);
    return info.isFile() || info.isDirectory();
  } catch {
    return false;
  }
}

async function readText(path) {
  return readFile(path, "utf8");
}
